function main({jsonString}) {
    // 解析JSON字符串（可能需要多次解析）
    let data = jsonString;

    // 如果data是字符串，继续解析直到得到数组
    while (typeof data === 'string') {
        data = JSON.parse(data);
    }

    // 确保data是数组
    if (!Array.isArray(data)) {
        return {
            markdownTable: '错误：输入数据不是数组格式'
        };
    }

    // 构建表格头部（只保留name和value列）
    let markdown = '| name | value |\n';
    markdown += '| --- | --- |\n';

    // 遍历数据构建表格行
    data.forEach(item => {
        const name = item.name || '';
        const value = item.value;

        // 如果value是数组
        if (Array.isArray(value)) {
            if (value.length === 0) {
                // 空数组的情况
                markdown += `| ${name} |  |\n`;
            } else {
                // 数组有元素，每个元素占一行
                value.forEach((val, index) => {
                    if (index === 0) {
                        // 第一行显示name
                        markdown += `| ${name} | ${val} |\n`;
                    } else {
                        // 后续行name留空
                        markdown += `|  | ${val} |\n`;
                    }
                });
            }
        } else {
            // value不是数组，直接显示
            markdown += `| ${name} | ${value} |\n`;
        }
    });

    return {
        markdownTable: markdown
    };
}

function main({tableData}) {
    // 定义需要提取的字段
    const targetFields = [
        '我方单位名称',
        '对方单位名称',
        '产品类别',
        '合同类型',
        '签订日期',
        '合同名称',
        '合同金额'
    ];

    // 按行分割输入数据
    const lines = tableData.trim().split('\n');

    // 存储提取的行
    const extractedRows = [];

    // 添加表头
    extractedRows.push('| name | value |');
    extractedRows.push('| --- | --- |');

    // 遍历每一行
    for (const line of lines) {
        // 跳过原表头和分隔线
        if (line.includes('name') && line.includes('value')) {
            continue;
        }
        if (line.includes('---')) {
            continue;
        }

        // 解析表格行
        const cells = line.split('|').map(cell => cell.trim()).filter(cell => cell);

        if (cells.length >= 2) {
            const fieldName = cells[0];
            const fieldValue = cells[1];

            // 检查是否是目标字段
            if (targetFields.includes(fieldName)) {
                extractedRows.push(`| ${fieldName} | ${fieldValue} |`);
            }
        }
    }

    // 构建新的Markdown表格
    const result = extractedRows.join('\n');

    return { result };
}

function main({data1}) {
    try {
        // 解析JSON字符串
        const parsedData = JSON.parse(data1);

        // 确保返回的是数组格式
        const result = Array.isArray(parsedData) ? parsedData : [parsedData];

        return {
            result: result
        };
    } catch (error) {
        // 如果解析失败，返回空数组和错误信息
        return {
            result: [],
            error: `JSON解析失败: ${error.message}`
        };
    }
}

function main({formData}) {
    // 查找type为"attachmentV2"的附件项
    const attachmentItem = formData.find(item => item.type === "attachmentV2");

    // 提取value数组，如果不存在则返回空数组
    const attachmentUrls = attachmentItem && Array.isArray(attachmentItem.value) 
        ? attachmentItem.value 
        : [];

    return {
        attachmentUrls
    };
}

