function main({inputText}) {
    // 将输入文本转换为对象
    const textObject = {
        text: inputText
    };

    // 将对象转换为压缩的JSON字符串（无空格、无换行）
    const compressedText = JSON.stringify(textObject);

    return {
        compressedText: compressedText
    };
}

