}

function main({text}) {
    // 按行分割字符串
    const lines = text.split('\n');

    // 在每行前面添加 "> " 标记
    const quotedLines = lines.map(line => `> ${line}`);

    // 重新组合成多行字符串
    const result = quotedLines.join('\n');

    return { result };
}
